.darma-loader-darma-custom-365 {color: var(--loader-color, #ca8a04);
  --loader-secondary-color: var(--loader-secondary-color, #fde047);
  --loader-bg: var(--loader-bg, #ffffff);
  width: 60px;
  aspect-ratio: 1;
  display: flex;
  animation: darma-loader-darma-custom-365-l12-0 4s infinite linear .5s;
}.darma-loader-darma-custom-365::before,.darma-loader-darma-custom-365::after {content: "";
  flex: 1;
  background: var(--loader-secondary-color, #fde047);
  clip-path: polygon(100% 0,100% 100%,0 50%);
  animation: darma-loader-darma-custom-365-l12-1 1s infinite linear;
}.darma-loader-darma-custom-365::after {transform: scale(-1);
  animation:none;
